import{_ as e,c as i,o as n,ag as l}from"./chunks/framework.DPDPlp3K.js";const s="/assets/%E6%9C%9F%E5%88%8A%E5%AD%A6%E7%A7%91%E5%88%86%E7%B1%BB.CI7cIfya.png",t="/assets/%E6%9C%9F%E5%88%8A%E5%88%86%E5%8C%BA.DSSENF39.png",S=JSON.parse('{"title":"如何选择期刊","description":"","frontmatter":{},"headers":[],"relativePath":"note/期刊.md","filePath":"note/期刊.md","lastUpdated":null}'),r={name:"note/期刊.md"};function c(o,a,p,h,d,u){return n(),i("div",null,a[0]||(a[0]=[l('<h1 id="如何选择期刊" tabindex="-1">如何选择期刊 <a class="header-anchor" href="#如何选择期刊" aria-label="Permalink to &quot;如何选择期刊&quot;">​</a></h1><p>在科研工作中，选择一本合适的期刊投稿是每位研究生的必修课。</p><h2 id="期刊分区" tabindex="-1">期刊分区 <a class="header-anchor" href="#期刊分区" aria-label="Permalink to &quot;期刊分区&quot;">​</a></h2><h3 id="中科院分区" tabindex="-1">中科院分区 <a class="header-anchor" href="#中科院分区" aria-label="Permalink to &quot;中科院分区&quot;">​</a></h3><p>中科院期刊分区是由中国科学院文献情报中心发布的期刊分类体系, 是国内广泛认可的学术评价标准.</p><p>中科院期刊分区将全球学术期刊按学科分为: 自然科学、社会科学和人文科学在内的21个大类。并根据影响因子（Impact Factor）高低，将每个学科的期刊划分为四个区：</p><ul><li>自然科学领域：数学、物理与天体物理、化学、材料科学、地球科学、生物学、农林科学、医学、工程技术、环境科学与生态学、计算机科学。</li><li>社会科学领域：经济学、管理学、心理学、社会学。</li><li>人文科学领域：艺术学、教育学、历史学、文学、哲学。</li></ul><p><img src="'+s+'" alt="期刊学科分类"></p><ul><li>一区：前5%的期刊，学术影响力顶尖</li><li>二区：前6%~20%，高水平期刊</li><li>三区：前21%~50%，中等水平</li><li>四区：剩余50%，影响力较低</li></ul><p>中科院分区具有时效性, 每年更新一次, 注意版本.</p><p>Top 的定义与标准: 大类学科中，1区期刊直接认定为 Top 期刊; 2区中少数期刊也会被认定为 Top 期刊, 通常是那些在各自小类学科中影响力较大、被广泛认可的期刊。</p><h3 id="jcr分区" tabindex="-1">JCR分区 <a class="header-anchor" href="#jcr分区" aria-label="Permalink to &quot;JCR分区&quot;">​</a></h3><p>JCR分区（Journal Citation Reports）由科睿唯安（原汤森路透）发布，对包括SCI 收录的期刊影响因子（Impact Factor）进行排序分区，按25%等比例划分四区形成JCR 期刊分区表。</p><ul><li>影响因子前25%的期刊为Q1区</li><li>影响因子位于25-50%为Q2区</li><li>影响因子位于50-75%为Q3区</li><li>影响因子位于75%之后的期刊为Q4区</li></ul><p>同一期刊在两种体系中的分区可能不同（例如某期刊在中科院是二区，JCR可能是一区）.</p><p><img src="'+t+`" alt="分区对比"></p><h3 id="sci是数据库" tabindex="-1">SCI是数据库 <a class="header-anchor" href="#sci是数据库" aria-label="Permalink to &quot;SCI是数据库&quot;">​</a></h3><p>SCI（Science Citation Index, 科学引文索引）, 是由美国科学信息研究所（ISI）创建的文献检索数据库，收录了全球众多自然科学领域的高质量学术期刊。</p><p>无论是中科院分区还是 JCR 分区，都是基于 SCI 收录的期刊进行的。</p><p>除了SCI, 中科院分区还针对SSCI、A&amp;HCI、ESCI和OAJ等数据库进行了分区.</p><p>SCIE (Science Citation Index Expanded, 科学引文索引扩展版）是 SCI 的网络版, 目前科睿唯安公司决定不再使用 SCI 的叫法，统一称为 SCIE，在其主期刊列表上只保留 SCIE 期刊目录, 中国科学技术信息研究所也声明依据 SCIE（网络版）数据进行科技论文产出统计.</p><p>SCI (Science Citation Index) 和 EI (Engineering Index) 都是最有影响力的二次文献数据库。</p><ul><li>一次文献：是直接发表出版的原始文献；</li><li>二次文献：是对一次文献进行加工整理后产生的文献，其包含题目、摘要等。</li></ul><h2 id="相关的公司和出版社" tabindex="-1">相关的公司和出版社 <a class="header-anchor" href="#相关的公司和出版社" aria-label="Permalink to &quot;相关的公司和出版社&quot;">​</a></h2><h3 id="clarivate-analytics-科睿唯安" tabindex="-1">Clarivate Analytics 科睿唯安 <a class="header-anchor" href="#clarivate-analytics-科睿唯安" aria-label="Permalink to &quot;Clarivate Analytics 科睿唯安&quot;">​</a></h3><p>Clarivate Analytics 的前身是 Thomson Reuters（汤森路透）知识产权与科技事业部。2016年，Onex Corporation 和 Baring Private Equity Asia 完成对汤森路透知识产权与科技业务的收购，将其改名为 Clarivate Analytics。</p><p>Clarivate Analytics 旗下的 Web of Science Group 是为全球科学研究社区提供信息与技术的供应商，其知名产品有：</p><ul><li>Web of Science (WoS)检索平台</li><li>EndNote 文献管理软件</li><li>Journal Citation Reports (JCR)期刊分区</li></ul><h4 id="web-of-science" tabindex="-1">Web of Science <a class="header-anchor" href="#web-of-science" aria-label="Permalink to &quot;Web of Science&quot;">​</a></h4><p>Web of Science（WoS） 是全球最大、覆盖学科最多的综合性学术信息资源，收录了自然科学、工程技术、生物医学等各个研究领域最具影响力的学术期刊，其最开始由 Institute for Scientific Information（ISI，科学信息研究所）创办，现在是由 Clarivate Analytics（科睿唯安）运营。</p><p>Web of Science 由多个数据库构成，包括:</p><ul><li>三个引文索引数据库（Science Citation Index Expanded、Social Science Citation Index、Arts &amp; Humanities Citation Index）</li><li>两个会议论文引文索引数据库（Conference Proceedings Citation Index - Science、Conference Proceedings Citation Index - Social Science &amp; Humanities）</li><li>两个化学信息数据库（Index Chemicus、Current Chemical Reactions）</li></ul><p>Web of Science 是最权威的 SCI (Science Citation Index)检索平台。</p><h3 id="elsevier-爱思唯尔" tabindex="-1">Elsevier 爱思唯尔 <a class="header-anchor" href="#elsevier-爱思唯尔" aria-label="Permalink to &quot;Elsevier 爱思唯尔&quot;">​</a></h3><p>爱思唯尔 (Elsevier)是一家全球专业从事科学与医学的信息分析公司, Elsevier 旗下的知名产品有：</p><ul><li>ScienceDirect</li><li>Scopus</li><li>Mendeley</li><li>Engineering Village</li></ul><p>爱思唯尔同时也是学术期刊出版商, 代表期刊有:</p><ul><li>《柳叶刀》（The Lancet）</li><li>《细胞》（Cell)</li><li>《四面体》（Tetrahedron）</li><li>...</li></ul><h4 id="sciencedirect" tabindex="-1">ScienceDirect <a class="header-anchor" href="#sciencedirect" aria-label="Permalink to &quot;ScienceDirect&quot;">​</a></h4><p>ScienceDirect 是爱思唯尔旗下知名的学术资源数据库.</p><h4 id="engineering-village" tabindex="-1">Engineering Village <a class="header-anchor" href="#engineering-village" aria-label="Permalink to &quot;Engineering Village&quot;">​</a></h4><p>Engineering Village 是爱思唯尔旗下的工程、应用科学领域文献检索平台. 包含了EI数据库, 可以作为 EI (The Engineering Index) 的检索平台.</p><p>EI (Engineering Index) 工程索引(可理解为目录)，是1884年由美国工程信息公司 (Engineering Information Inc.) 出版的工程技术领域最权威的检索工具。</p><h3 id="springer-nature-施普林格・自然" tabindex="-1">Springer Nature 施普林格・自然 <a class="header-anchor" href="#springer-nature-施普林格・自然" aria-label="Permalink to &quot;Springer Nature 施普林格・自然&quot;">​</a></h3><p>施普林格・自然（Springer Nature）是一家全球领先的学术出版公司, 代表期刊有:</p><ul><li>《自然》及《自然》系列期刊</li><li>Advanced Fiber Materials</li><li>Cellulose</li><li>...</li></ul><h3 id="acs-美国化学会" tabindex="-1">ACS 美国化学会 <a class="header-anchor" href="#acs-美国化学会" aria-label="Permalink to &quot;ACS 美国化学会&quot;">​</a></h3><p>ACS Publications 是美国化学会（American Chemical Society）的出版物平台, 代表期刊有:</p><ul><li>Chemical Reviews</li><li>Accounts of Chemical Research</li><li>Macromolecules</li><li>...</li></ul><h3 id="aaas-美国科学促进会" tabindex="-1">AAAS 美国科学促进会 <a class="header-anchor" href="#aaas-美国科学促进会" aria-label="Permalink to &quot;AAAS 美国科学促进会&quot;">​</a></h3><p>美国科学促进会（American Association for the Advancement of Science—AAAS）成立于 1848 年，是世界上最大的科学和工程学协会的联合体，也是最大的非营利性国际科技组织.</p><p>例如大名鼎鼎的《科学》（Science）杂志由美国科学促进会出版.</p><h3 id="ieee" tabindex="-1">IEEE <a class="header-anchor" href="#ieee" aria-label="Permalink to &quot;IEEE&quot;">​</a></h3><p>IEEE，全称 Institute of Electrical and Electronics Engineers（电气和电子工程师协会），是于1963年由美国电气工程师协会（AIEE）和无线电工程师协会（IRE）合并而成，是世界上最大的非营利性专业技术学会。</p><h2 id="如何快速查询期刊分区" tabindex="-1">如何快速查询期刊分区 <a class="header-anchor" href="#如何快速查询期刊分区" aria-label="Permalink to &quot;如何快速查询期刊分区&quot;">​</a></h2><ol><li>通过(中科院文献情报中心)[<a href="https://www.fenqubiao.com/" target="_blank" rel="noreferrer">https://www.fenqubiao.com/</a>]（最权威, 需注册账号登录使用）</li><li>利用第三方服务网站, 例如<a href="https://www.letpub.com.cn/" target="_blank" rel="noreferrer">LetPub</a>.</li><li>利用一些微信公众号: 例如搜索关键词&quot;期刊分区表&quot;</li><li>浏览器插件, 例如EasyScholar, 可在浏览文章的网页时直接显示期刊分区</li></ol><p>注意: 警惕虚假网站, 部分网站提供免费分区查询但数据不准确, 通过多平台对比, 可确保信息准确无误</p><h2 id="如何快速定位合适的期刊" tabindex="-1">如何快速定位合适的期刊 <a class="header-anchor" href="#如何快速定位合适的期刊" aria-label="Permalink to &quot;如何快速定位合适的期刊&quot;">​</a></h2><ol><li>通过平时阅读的参考文献快速定位合适的期刊.</li><li>2025年中科院分区的自然科学领域分类中, 按照学科相关性, 优先考虑以下分类:</li></ol><div class="language-相关学科分类 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">相关学科分类</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌── 化学</span></span>
<span class="line"><span>│   ├── 晶体学</span></span>
<span class="line"><span>│   │   ├── Crystal Growth &amp; Design</span></span>
<span class="line"><span>│   │   └── Crystals</span></span>
<span class="line"><span>│   └── 高分子科学</span></span>
<span class="line"><span>│       ├── MACROMOLECULES</span></span>
<span class="line"><span>│       └── </span></span>
<span class="line"><span>├── 材料科学</span></span>
<span class="line"><span>│   ├── 纳米科技</span></span>
<span class="line"><span>│   └── </span></span>
<span class="line"><span>├── 生物学</span></span>
<span class="line"><span>│   ├── 应用化学</span></span>
<span class="line"><span>│   └── </span></span>
<span class="line"><span>└── 工程技术</span></span>
<span class="line"><span>     ├── 应用化学</span></span>
<span class="line"><span>     └── 工程:化工</span></span></code></pre></div>`,60)]))}const b=e(r,[["render",c]]);export{S as __pageData,b as default};
